  ('elementary-0a2fc18c-moex-00149', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設小悟割一片草需要2小時、砍一棵樹需要1小時；而小空割一片草需要3小時、砍一棵樹需要2小 時。下列敘述何者正確？', '["小悟對割草具比較利益，而小空對砍樹具絕對利益", "小悟對割草具絕對利益，而小空對砍樹具比較利益", "小悟對砍樹具比較利益，而小空對割草具比較利益", "小悟對割草具絕對利益，而小空對砍樹具絕對利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00150', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-114-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '在有效的進口配額管制之下，配額會造成進口國產生何種影響？', '["國內價格上升", "國內產業供給量減少", "均衡交易數量增加", "消費者可以買到更多的進口貨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:14+00:00", "source_pdf_sha1": "da6a047c014b", "answer_pdf_sha1": "5b18e8f0e844", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "514", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
